'use client'

import { Suspense, useState, useMemo, useEffect, useRef } from 'react'
import { useRouter, useSearchParams } from 'next/navigation'
import DashboardLayout from '@/components/DashboardLayout'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group'
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from '@/components/ui/dialog'
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'
import { Search, Plus, Check, User, FileText, Loader2, RefreshCw, Pencil } from 'lucide-react'
import { toast } from 'sonner'
import { useApiClient } from '@/hooks/useApiClient'
import { useCachedData } from '@/hooks/useCachedData'
import type { Client, Service, CreateClientRequest } from '@/types'
import { normalizeClients, normalizeServices } from '@/lib/normalizers'
import { CACHE_KEYS, removeCache } from '@/lib/localCache'
import { isLicenseActive } from '@/lib/licenseGuard'
import { LicenseExpiredModal, type LicenseBlockReason } from '@/components/LicenseExpiredModal'
import { formatMoney, extractMoneyDigits, moneyDigitsToNumber, numberToMoneyDigits, formatPercent, percentDigitsToNumber, formatPhone, extractPhoneDigits, formatCnpj, extractCnpjDigits, formatCpf, extractCpfDigits, formatCep, extractCepDigits } from '@/lib/masks'
import { isValidCpf, isValidCnpj } from '@/lib/validators'
import { ESTADOS } from '@/lib/constants'
import { MunicipioAutocomplete } from '@/components/MunicipioAutocomplete'

const avatarColors = [
  'from-[#7C3AED] to-[#6D28D9]', // purple
  'from-blue-500 to-blue-600',
  'from-green-500 to-green-600',
  'from-orange-500 to-orange-600',
  'from-pink-500 to-pink-600',
  'from-teal-500 to-teal-600',
]

function getAvatarColor(index: number): string {
  return avatarColors[index % avatarColors.length]
}

function toClientPayload(c: CreateClientRequest) {
  return {
    cpf_cnpj: c.document.replace(/\D/g, ''),
    company_name: c.razaoSocial.trim(),
    municipalRegistration: '',
    email: (c.email ?? '').trim(),
    postal_code: (c.cep ?? '').replace(/\D/g, ''),
    cityCode: (c.codigoMunicipio ?? '').replace(/\D/g, ''),
    address: (c.logradouro ?? '').trim(),
    number: (c.numero ?? '').trim(),
    complement: (c.complemento ?? '').trim(),
    neighborhood: (c.bairro ?? '').trim(),
    state: (c.estado ?? '').trim().toUpperCase(),
    city: (c.municipio ?? '').trim(),
    phone: (c.phone ?? '').replace(/\D/g, ''),
  }
}

function NovaNotaPageContent() {
  const router = useRouter()
  const searchParams = useSearchParams()
  const { apiFetch } = useApiClient()

  // ---------- Cached data ----------
  const {
    data: clients,
    isLoading: loadingClients,
    reload: reloadClients,
    updateCache: updateClientsCache,
  } = useCachedData<Client[]>({
    cacheKey: CACHE_KEYS.CLIENTS,
    apiUrl: '/api/clients',
    normalize: normalizeClients,
  })

  const {
    data: services,
    isLoading: loadingServices,
    reload: reloadServices,
  } = useCachedData<Service[]>({
    cacheKey: CACHE_KEYS.SERVICES,
    apiUrl: '/api/configuracoes/servicos',
    normalize: normalizeServices,
  })

  // ---------- License check ----------
  const [showLicenseModal, setShowLicenseModal] = useState(false)
  const [licenseModalReason, setLicenseModalReason] = useState<LicenseBlockReason>('license_expired')

  useEffect(() => {
    if (!isLicenseActive()) {
      setShowLicenseModal(true)
    }
  }, [])

  // ---------- State ----------
  const [reloadingClients, setReloadingClients] = useState(false)
  const [reloadingServices, setReloadingServices] = useState(false)
  const [step, setStep] = useState<'clients' | 'service' | 'review'>('clients')
  const [selectedClient, setSelectedClient] = useState<Client | null>(null)
  const [selectedClientIndex, setSelectedClientIndex] = useState<number>(0)
  const [selectedService, setSelectedService] = useState('')
  const [serviceValue, setServiceValue] = useState('')
  const [issRetido, setIssRetido] = useState(false)
  const [responsavelRetencao, setResponsavelRetencao] = useState('TOMADOR')
  const [aliquotaIss, setAliquotaIss] = useState('')
  const [valorTotalRetido, setValorTotalRetido] = useState('')
  const [showNewClientModal, setShowNewClientModal] = useState(false)
  const [editingClientId, setEditingClientId] = useState<string | null>(null)
  const [showSuccessModal, setShowSuccessModal] = useState(false)
  const [sendCopy, setSendCopy] = useState(false)
  const [searchTerm, setSearchTerm] = useState('')
  const [emitting, setEmitting] = useState(false)
  const [savingClient, setSavingClient] = useState(false)
  const [emittedNoteNumber, setEmittedNoteNumber] = useState('')
  const [emittedNoteId, setEmittedNoteId] = useState('')

  const [newClientData, setNewClientData] = useState<CreateClientRequest>({
    razaoSocial: '',
    documentType: 'CPF',
    document: '',
    email: '',
    phone: '',
    cep: '',
    logradouro: '',
    numero: '',
    complemento: '',
    bairro: '',
    estado: '',
    municipio: '',
  })

  const [clientErrors, setClientErrors] = useState<Record<string, string>>({})

  const validateClient = (): Record<string, string> => {
    const errs: Record<string, string> = {}
    if (!newClientData.razaoSocial.trim()) errs.razaoSocial = 'Razão Social é obrigatória'
    const docDigits = newClientData.document.replace(/\D/g, '')
    const isCpf = newClientData.documentType === 'CPF'
    if (!docDigits) {
      errs.document = `${newClientData.documentType} é obrigatório`
    } else if (isCpf ? !isValidCpf(docDigits) : !isValidCnpj(docDigits)) {
      errs.document = `${newClientData.documentType} inválido`
    }
    const phoneDigits = (newClientData.phone ?? '').replace(/\D/g, '')
    if (phoneDigits && (phoneDigits.length < 10 || phoneDigits.length > 11)) {
      errs.phone = 'Telefone inválido'
    }
    const cepDigits = (newClientData.cep ?? '').replace(/\D/g, '')
    if (cepDigits && cepDigits.length !== 8) {
      errs.cep = 'CEP inválido'
    }
    const email = newClientData.email ?? ''
    if (email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      errs.email = 'Email inválido'
    }
    return errs
  }

  useEffect(() => {
    setClientErrors(prev => {
      if (Object.keys(prev).length === 0) return prev
      const next = { ...prev }
      let changed = false
      if (prev.razaoSocial && newClientData.razaoSocial.trim()) { delete next.razaoSocial; changed = true }
      if (prev.document) {
        const d = newClientData.document.replace(/\D/g, '')
        const valid = newClientData.documentType === 'CPF' ? isValidCpf(d) : isValidCnpj(d)
        if (valid) { delete next.document; changed = true }
      }
      if (prev.phone) {
        const d = (newClientData.phone ?? '').replace(/\D/g, '')
        if (!d || (d.length >= 10 && d.length <= 11)) { delete next.phone; changed = true }
      }
      if (prev.cep) {
        const d = (newClientData.cep ?? '').replace(/\D/g, '')
        if (!d || d.length === 8) { delete next.cep; changed = true }
      }
      if (prev.email) {
        const e = newClientData.email ?? ''
        if (!e || /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e)) { delete next.email; changed = true }
      }
      return changed ? next : prev
    })
  }, [newClientData.razaoSocial, newClientData.document, newClientData.documentType, newClientData.phone, newClientData.cep, newClientData.email])

  // ---------- Duplicate handling ----------
  const isDuplicate = searchParams.get('duplicate') === 'true'
  const duplicateHandled = useRef(false)

  useEffect(() => {
    if (!isDuplicate || duplicateHandled.current) return
    if (!clients || clients.length === 0) return
    if (!services || services.length === 0) return
    duplicateHandled.current = true

    const clientDocument = searchParams.get('clientDocument') || ''
    const clientName = searchParams.get('clientName') || ''
    const paramServiceId = searchParams.get('serviceId') || ''
    const paramServiceValue = searchParams.get('serviceValue') || ''

    // Find matching client by cpfCnpj, fallback to companyName
    let clientIndex = clients.findIndex((c) => c.cpfCnpj === clientDocument)
    if (clientIndex === -1 && clientName) {
      clientIndex = clients.findIndex((c) => c.companyName === clientName)
    }
    if (clientIndex !== -1) {
      const client = clients[clientIndex]
      setSelectedClient(client)
      setSelectedClientIndex(clientIndex)
    }

    // Pre-fill service value (convert number string like "200" to money digits like "20000")
    if (paramServiceValue) {
      const numValue = parseFloat(paramServiceValue)
      if (!isNaN(numValue)) {
        setServiceValue(numberToMoneyDigits(numValue))
      }
    }

    // Try to match service by id
    if (paramServiceId) {
      const matchedService = services.find((s) => s.id === paramServiceId)
      if (matchedService) {
        setSelectedService(matchedService.id)
      }
    }

    // Jump to service step
    setStep('service')
  }, [isDuplicate, clients, services, searchParams])

  // ---------- Derived ----------
  const filteredClients = useMemo(
    () =>
      (clients || []).filter(
        (c) =>
          c.companyName.toLowerCase().includes(searchTerm.toLowerCase()) ||
          c.cpfCnpj.includes(searchTerm)
      ),
    [clients, searchTerm]
  )

  const selectedServiceData = useMemo(
    () => (services || []).find((s) => s.id === selectedService),
    [services, selectedService]
  )

  const numericValue = moneyDigitsToNumber(serviceValue)
  const numericAliquota = percentDigitsToNumber(aliquotaIss)
  const numericValorRetido = moneyDigitsToNumber(valorTotalRetido)
  const calculatedIss = issRetido ? (numericValue * (numericAliquota / 100)).toFixed(2) : '0.00'
  const totalValue = numericValue.toFixed(2)
  const netValue = issRetido ? (numericValue - numericValorRetido).toFixed(2) : totalValue

  // ---------- Handlers ----------
  const handleClientSelect = (client: Client, index: number) => {
    if (!isLicenseActive()) {
      setShowLicenseModal(true)
      return
    }
    setSelectedClient(client)
    setSelectedClientIndex(index)
    setStep('service')
  }

  const handleContinue = () => {
    if (!selectedService || !serviceValue) {
      toast.error('Preencha todos os campos obrigatórios')
      return
    }
    setStep('review')
  }

  const handleConfirmEmit = async () => {
    if (!selectedClient || !selectedServiceData) return
    // Checa licença antes de emitir
    if (!isLicenseActive()) {
      setShowLicenseModal(true)
      return
    }
    setEmitting(true)
    try {
      const res = await apiFetch('/api/nfse/emitir', {
        method: 'POST',
        body: JSON.stringify({
          valorServico: numericValue,
          ambiente: 'HOMOLOGACAO',
          clientId: selectedClient.id,
          serviceId: selectedServiceData.id,
          descricaoServico: selectedServiceData.description || selectedServiceData.name,
          issRetido,
          ...(issRetido && {
            responsavelRetencao,
            aliquotaIss: numericAliquota,
            valorTotalRetido: numericValorRetido,
          }),
        }),
      })

      if (!res.ok) {
        const err = await res.json().catch(() => null)
        if (res.status === 402) {
          const reason = err?.reason as LicenseBlockReason | undefined
          setLicenseModalReason(reason || 'license_expired')
          setShowLicenseModal(true)
          return
        }
        throw new Error(err?.message || 'Erro ao emitir nota')
      }

      const data = await res.json()
      setEmittedNoteNumber(data?.numeroNota || '')
      setEmittedNoteId(data?.id || '')
      setShowSuccessModal(true)
      // Invalidar caches que dependem de notas
      removeCache(CACHE_KEYS.NOTES)
      removeCache(CACHE_KEYS.DASHBOARD)
      toast.success('Nota fiscal emitida com sucesso!')
    } catch (err: unknown) {
      const error = err as Error
      toast.error(error.message || 'Erro ao emitir nota fiscal')
    } finally {
      setEmitting(false)
    }
  }

  const handleSaveNewClient = async () => {
    const errs = validateClient()
    if (Object.keys(errs).length > 0) {
      setClientErrors(errs)
      toast.error('Preencha os campos obrigatórios')
      return
    }
    setClientErrors({})
    setSavingClient(true)
    try {
      const res = await apiFetch('/api/clients', {
        method: 'POST',
        body: JSON.stringify(toClientPayload(newClientData)),
      })

      if (!res.ok) {
        const err = await res.json().catch(() => null)
        throw new Error(err?.message || 'Erro ao cadastrar cliente')
      }

      toast.success('Cliente cadastrado com sucesso!')
      setShowNewClientModal(false)
      setNewClientData({
        razaoSocial: '',
        documentType: 'CPF',
        document: '',
        email: '',
        phone: '',
        cep: '',
        logradouro: '',
        numero: '',
        complemento: '',
        bairro: '',
        estado: '',
        municipio: '',
      })
      // Reload clients cache after creating new client
      await reloadClients()
    } catch (err: unknown) {
      const error = err as Error
      toast.error(error.message || 'Erro ao cadastrar cliente')
    } finally {
      setSavingClient(false)
    }
  }

  const handleEditClient = (client: Client, e: React.MouseEvent) => {
    e.stopPropagation()
    setEditingClientId(client.id)
    setNewClientData({
      razaoSocial: client.companyName,
      documentType: client.documentType,
      document: client.cpfCnpj,
      email: client.email || '',
      phone: client.phone || '',
      cep: client.address?.cep || '',
      logradouro: client.address?.logradouro || '',
      numero: client.address?.numero || '',
      complemento: client.address?.complemento || '',
      bairro: client.address?.bairro || '',
      estado: client.address?.estado || '',
      municipio: client.address?.municipio || '',
    })
    setShowNewClientModal(true)
  }

  const handleSaveEditClient = async () => {
    if (!editingClientId) return
    const errs = validateClient()
    if (Object.keys(errs).length > 0) {
      setClientErrors(errs)
      toast.error('Preencha os campos obrigatórios')
      return
    }
    setClientErrors({})
    setSavingClient(true)
    try {
      const res = await apiFetch(`/api/clients/${editingClientId}`, {
        method: 'PUT',
        body: JSON.stringify(toClientPayload(newClientData)),
      })
      if (!res.ok) {
        const err = await res.json().catch(() => null)
        throw new Error(err?.message || 'Erro ao atualizar cliente')
      }
      toast.success('Cliente atualizado com sucesso!')
      setShowNewClientModal(false)
      setEditingClientId(null)
      setNewClientData({
        razaoSocial: '', documentType: 'CPF', document: '', email: '', phone: '',
        cep: '', logradouro: '', numero: '', complemento: '', bairro: '', estado: '', municipio: '',
      })
      await reloadClients()
    } catch (err: unknown) {
      const error = err as Error
      toast.error(error.message || 'Erro ao atualizar cliente')
    } finally {
      setSavingClient(false)
    }
  }

  const resetWizard = () => {
    setShowSuccessModal(false)
    setStep('clients')
    setSelectedClient(null)
    setSelectedService('')
    setServiceValue('')
    setSendCopy(false)
    setIssRetido(false)
    setResponsavelRetencao('TOMADOR')
    setAliquotaIss('')
    setValorTotalRetido('')
    setEmittedNoteNumber('')
    setEmittedNoteId('')
  }

  const licenseModal = <LicenseExpiredModal open={showLicenseModal} reason={licenseModalReason} onClose={() => setShowLicenseModal(false)} />

  // ====================================================
  // STEP 1 - CLIENT SELECTION
  // ====================================================
  if (step === 'clients') {
    return (
      <DashboardLayout>
        {licenseModal}
        <div className="min-h-screen bg-background p-4 sm:p-6 lg:p-8">
          <div className="max-w-5xl mx-auto">
            <div className="mb-8 relative">
              <div className="hidden dark:block absolute inset-0 bg-[#7C3AED]/10 rounded-3xl -z-10"></div>
              <div className="py-6 px-6">
                <h1 className="text-2xl sm:text-3xl lg:text-4xl font-bold text-foreground mb-2">Nova Nota Fiscal</h1>
                <p className="text-muted-foreground">Selecione o cliente para iniciar a emissão</p>
              </div>
            </div>

            <Card className="border-none shadow-xl">
              <CardHeader className="border-b dark:bg-muted/40">
                <div className="flex items-center justify-between">
                  <div>
                    <CardTitle className="text-xl">Selecionar Cliente</CardTitle>
                    <p className="text-sm text-muted-foreground mt-1">
                      Escolha ou cadastre um novo cliente
                    </p>
                  </div>
                  <button onClick={async () => { setReloadingClients(true); await reloadClients(); setReloadingClients(false); toast.success('Clientes atualizados') }} disabled={reloadingClients} className="p-2 rounded-lg hover:bg-muted text-muted-foreground hover:text-[#7C3AED] transition-colors disabled:opacity-50" title="Recarregar clientes"><RefreshCw className={`w-5 h-5 ${reloadingClients ? 'animate-spin' : ''}`} /></button>
                </div>
              </CardHeader>
              <CardContent className="space-y-4 pt-6">
                <div className="flex gap-3">
                  <div className="flex-1 relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-muted-foreground" />
                    <Input
                      placeholder="Buscar por nome ou documento..."
                      className="pl-10 h-12 border-border focus:border-[#7C3AED] focus:ring-[#7C3AED]"
                      value={searchTerm}
                      onChange={(e) => setSearchTerm(e.target.value)}
                    />
                  </div>
                  <Button
                    onClick={() => setShowNewClientModal(true)}
                    className="bg-gradient-to-r from-[#7C3AED] to-[#6D28D9] hover:from-[#6D28D9] hover:to-[#5B21B6] text-white h-12 px-6 shadow-lg hover:shadow-xl transition-all duration-200"
                  >
                    <Plus className="w-5 h-5 mr-2" />
                    Novo Cliente
                  </Button>
                </div>

                {loadingClients ? (
                  <div className="flex items-center justify-center py-12">
                    <Loader2 className="w-8 h-8 text-[#7C3AED] animate-spin" />
                    <span className="ml-3 text-muted-foreground">Carregando clientes...</span>
                  </div>
                ) : filteredClients.length === 0 ? (
                  <div className="text-center py-12 text-muted-foreground">
                    <User className="w-12 h-12 mx-auto mb-3 text-muted-foreground" />
                    <p className="font-medium">Nenhum cliente encontrado</p>
                    <p className="text-sm mt-1">Cadastre um novo cliente para continuar</p>
                  </div>
                ) : (
                  <div className="space-y-3">
                    {filteredClients.map((client, index) => (
                      <div
                        key={client.id}
                        onClick={() => handleClientSelect(client, index)}
                        className="p-5 border-2 border-border rounded-xl hover:border-[#7C3AED] hover:bg-[#FAF5FF] dark:hover:bg-[#7C3AED]/10 cursor-pointer transition-all duration-200 group"
                      >
                        <div className="flex items-center justify-between">
                          <div className="flex items-center gap-4">
                            <div className={`w-12 h-12 rounded-full bg-gradient-to-br ${getAvatarColor(index)} flex items-center justify-center text-white font-bold text-lg shadow-lg`}>
                              {client.companyName.charAt(0)}
                            </div>
                            <div>
                              <p className="font-semibold text-foreground group-hover:text-[#7C3AED] transition-colors">
                                {client.companyName}
                              </p>
                              <p className="text-sm text-muted-foreground">
                                {client.documentType}: {client.cpfCnpj}
                              </p>
                            </div>
                          </div>
                          <button
                            onClick={(e) => handleEditClient(client, e)}
                            className="p-2 rounded-lg text-muted-foreground hover:text-[#7C3AED] hover:bg-[#FAF5FF] dark:hover:bg-[#7C3AED]/10 transition-colors sm:opacity-0 sm:group-hover:opacity-100"
                            title="Editar cliente"
                          >
                            <Pencil className="w-4 h-4" />
                          </button>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </CardContent>
            </Card>
          </div>

          {/* New Client Modal */}
          <Dialog open={showNewClientModal} onOpenChange={(open) => { setShowNewClientModal(open); if (!open) { setEditingClientId(null); setClientErrors({}) } }}>
            <DialogContent className="sm:max-w-5xl max-h-[90vh] overflow-y-auto p-0">
              {/* Header */}
              <div className="px-8 pt-8 pb-4">
                <DialogHeader>
                  <DialogTitle className="text-xl font-bold text-foreground">{editingClientId ? 'Editar Cliente' : 'Novo Cliente'}</DialogTitle>
                  <DialogDescription className="text-muted-foreground">
                    {editingClientId ? 'Atualize os dados do cliente' : 'Preencha os dados do cliente para cadastrá-lo no sistema'}
                  </DialogDescription>
                </DialogHeader>
              </div>

              <div className="px-8 pb-8 space-y-6">
                {/* Dados Pessoais */}
                <div className="space-y-4">
                  <h3 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider">Dados Pessoais</h3>

                  <div className="space-y-1.5">
                    <Label className="text-sm text-foreground">Razão Social / Nome Completo</Label>
                    <Input
                      value={newClientData.razaoSocial}
                      onChange={(e) =>
                        setNewClientData({ ...newClientData, razaoSocial: e.target.value })
                      }
                      placeholder="Digite o nome completo ou razão social"
                      className="h-11 bg-card border-border"
                      aria-invalid={!!clientErrors.razaoSocial}
                    />
                    {clientErrors.razaoSocial && <p className="text-sm text-red-500">{clientErrors.razaoSocial}</p>}
                  </div>

                  <div className="space-y-1.5">
                    <Label className="text-sm text-foreground">Tipo de Documento</Label>
                    <div className="flex gap-3">
                      <button
                        type="button"
                        onClick={() => setNewClientData({ ...newClientData, documentType: 'CPF', document: '' })}
                        className={`flex-1 h-11 rounded-lg border-2 font-medium text-sm transition-all ${
                          newClientData.documentType === 'CPF'
                            ? 'border-[#7C3AED] bg-[#FAF5FF] text-[#7C3AED]'
                            : 'border-border bg-card text-muted-foreground hover:border-border'
                        }`}
                      >
                        CPF - Pessoa Física
                      </button>
                      <button
                        type="button"
                        onClick={() => setNewClientData({ ...newClientData, documentType: 'CNPJ', document: '' })}
                        className={`flex-1 h-11 rounded-lg border-2 font-medium text-sm transition-all ${
                          newClientData.documentType === 'CNPJ'
                            ? 'border-[#7C3AED] bg-[#FAF5FF] text-[#7C3AED]'
                            : 'border-border bg-card text-muted-foreground hover:border-border'
                        }`}
                      >
                        CNPJ - Pessoa Jurídica
                      </button>
                    </div>
                  </div>

                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                    <div className="space-y-1.5">
                      <Label className="text-sm text-foreground">{newClientData.documentType}</Label>
                      <Input
                        inputMode="numeric"
                        value={
                          newClientData.documentType === 'CPF'
                            ? formatCpf(newClientData.document)
                            : formatCnpj(newClientData.document)
                        }
                        onChange={(e) =>
                          setNewClientData({
                            ...newClientData,
                            document:
                              newClientData.documentType === 'CPF'
                                ? extractCpfDigits(e.target.value)
                                : extractCnpjDigits(e.target.value),
                          })
                        }
                        placeholder={
                          newClientData.documentType === 'CPF'
                            ? '000.000.000-00'
                            : '00.000.000/0000-00'
                        }
                        className="h-11 bg-card border-border"
                        aria-invalid={!!clientErrors.document}
                      />
                      {clientErrors.document && <p className="text-sm text-red-500">{clientErrors.document}</p>}
                    </div>
                    <div className="space-y-1.5">
                      <Label className="text-sm text-foreground">Email</Label>
                      <Input
                        type="email"
                        value={newClientData.email}
                        onChange={(e) =>
                          setNewClientData({ ...newClientData, email: e.target.value })
                        }
                        placeholder="email@exemplo.com"
                        className="h-11 bg-card border-border"
                        aria-invalid={!!clientErrors.email}
                      />
                      {clientErrors.email && <p className="text-sm text-red-500">{clientErrors.email}</p>}
                    </div>
                  </div>

                  <div className="space-y-1.5">
                    <Label className="text-sm text-foreground">Telefone</Label>
                    <Input
                      inputMode="numeric"
                      value={formatPhone(newClientData.phone ?? '')}
                      onChange={(e) =>
                        setNewClientData({ ...newClientData, phone: extractPhoneDigits(e.target.value) })
                      }
                      placeholder="(00) 00000-0000"
                      className="h-11 bg-card border-border max-w-xs"
                      aria-invalid={!!clientErrors.phone}
                    />
                    {clientErrors.phone && <p className="text-sm text-red-500">{clientErrors.phone}</p>}
                  </div>
                </div>

                {/* Divider */}
                <div className="border-t border-border" />

                {/* Endereço */}
                <div className="space-y-4">
                  <h3 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider">Endereço</h3>

                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                    <div className="space-y-1.5">
                      <Label className="text-sm text-foreground">CEP</Label>
                      <Input
                        inputMode="numeric"
                        value={formatCep(newClientData.cep ?? '')}
                        onChange={(e) =>
                          setNewClientData({ ...newClientData, cep: extractCepDigits(e.target.value) })
                        }
                        placeholder="00000-000"
                        className="h-11 bg-card border-border"
                        aria-invalid={!!clientErrors.cep}
                      />
                      {clientErrors.cep && <p className="text-sm text-red-500">{clientErrors.cep}</p>}
                    </div>
                    <div className="space-y-1.5 col-span-2">
                      <Label className="text-sm text-foreground">Logradouro</Label>
                      <Input
                        value={newClientData.logradouro}
                        onChange={(e) =>
                          setNewClientData({ ...newClientData, logradouro: e.target.value })
                        }
                        placeholder="Rua, Avenida..."
                        className="h-11 bg-card border-border"
                      />
                    </div>
                  </div>

                  <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
                    <div className="space-y-1.5">
                      <Label className="text-sm text-foreground">Número</Label>
                      <Input
                        value={newClientData.numero}
                        onChange={(e) =>
                          setNewClientData({ ...newClientData, numero: e.target.value })
                        }
                        placeholder="123"
                        className="h-11 bg-card border-border"
                      />
                    </div>
                    <div className="space-y-1.5 col-span-2">
                      <Label className="text-sm text-foreground">Complemento</Label>
                      <Input
                        value={newClientData.complemento}
                        onChange={(e) =>
                          setNewClientData({ ...newClientData, complemento: e.target.value })
                        }
                        placeholder="Apto, Sala..."
                        className="h-11 bg-card border-border"
                      />
                    </div>
                    <div className="space-y-1.5">
                      <Label className="text-sm text-foreground">Bairro</Label>
                      <Input
                        value={newClientData.bairro}
                        onChange={(e) =>
                          setNewClientData({ ...newClientData, bairro: e.target.value })
                        }
                        placeholder="Nome do bairro"
                        className="h-11 bg-card border-border"
                      />
                    </div>
                  </div>

                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                    <div className="space-y-1.5">
                      <Label className="text-sm text-foreground">Estado</Label>
                      <Select
                        value={newClientData.estado}
                        onValueChange={(value) =>
                          setNewClientData({ ...newClientData, estado: value })
                        }
                      >
                        <SelectTrigger className="h-11 bg-card border-border">
                          <SelectValue placeholder="Selecione o estado" />
                        </SelectTrigger>
                        <SelectContent>
                          {ESTADOS.map((estado) => (
                            <SelectItem key={estado} value={estado}>
                              {estado}
                            </SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                    </div>
                    <div className="space-y-1.5">
                      <Label className="text-sm text-foreground">Município</Label>
                      <MunicipioAutocomplete
                        value={newClientData.municipio || ''}
                        estado={newClientData.estado || ''}
                        onChange={(name, code) =>
                          setNewClientData({ ...newClientData, municipio: name, codigoMunicipio: code })
                        }
                      />
                    </div>
                  </div>
                </div>

                {/* Divider */}
                <div className="border-t border-border" />

                {/* Actions */}
                <div className="flex gap-3">
                  <Button
                    variant="outline"
                    onClick={() => { setShowNewClientModal(false); setClientErrors({}) }}
                    className="flex-1 h-11"
                    disabled={savingClient}
                  >
                    Cancelar
                  </Button>
                  <Button
                    onClick={editingClientId ? handleSaveEditClient : handleSaveNewClient}
                    className="flex-1 h-11 bg-[#7C3AED] hover:bg-[#6D28D9] text-white"
                    disabled={savingClient}
                  >
                    {savingClient ? (
                      <>
                        <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                        Salvando...
                      </>
                    ) : editingClientId ? (
                      'Salvar Alterações'
                    ) : (
                      'Salvar Cliente'
                    )}
                  </Button>
                </div>
              </div>
            </DialogContent>
          </Dialog>
        </div>
      </DashboardLayout>
    )
  }

  // ====================================================
  // STEP 2 - SERVICE SELECTION
  // ====================================================
  if (step === 'service') {
    return (
      <DashboardLayout>
        {licenseModal}
        <div className="min-h-screen bg-background p-4 sm:p-6 lg:p-8">
          <div className="max-w-4xl mx-auto">
            {/* Progress bar */}
            <div className="mb-8">
              <div className="flex items-center justify-center gap-2 sm:gap-3 mb-6">
                <button onClick={() => setStep('clients')} className="flex items-center gap-1.5 sm:gap-2 cursor-pointer">
                  <div className="w-8 h-8 sm:w-10 sm:h-10 rounded-full bg-gradient-to-r from-[#7C3AED] to-[#6D28D9] text-white flex items-center justify-center font-bold shadow-lg">
                    <Check className="w-4 h-4 sm:w-5 sm:h-5" />
                  </div>
                  <span className="text-xs sm:text-sm font-medium text-[#7C3AED]">Cliente</span>
                </button>
                <div className="w-8 sm:w-20 h-1 bg-gradient-to-r from-[#7C3AED] to-[#6D28D9]"></div>
                <div className="flex items-center gap-1.5 sm:gap-2">
                  <div className="w-8 h-8 sm:w-10 sm:h-10 rounded-full bg-gradient-to-r from-[#7C3AED] to-[#6D28D9] text-white flex items-center justify-center font-bold shadow-lg text-sm sm:text-base">
                    2
                  </div>
                  <span className="text-xs sm:text-sm font-medium text-[#7C3AED]">Serviço</span>
                </div>
                <div className="w-8 sm:w-20 h-1 bg-muted"></div>
                <div className="flex items-center gap-1.5 sm:gap-2">
                  <div className="w-8 h-8 sm:w-10 sm:h-10 rounded-full bg-muted text-muted-foreground flex items-center justify-center font-bold text-sm sm:text-base">
                    3
                  </div>
                  <span className="text-xs sm:text-sm font-medium text-muted-foreground">Revisão</span>
                </div>
              </div>
            </div>

            {/* Client Info Card (collapsible) */}
            {selectedClient ? (
              <Card className="border-none shadow-md mb-6">
                <CardContent className="p-5">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3">
                      <div className={`w-10 h-10 rounded-xl bg-gradient-to-br ${getAvatarColor(selectedClientIndex)} flex items-center justify-center text-white font-bold shadow`}>
                        {selectedClient.companyName.charAt(0)}
                      </div>
                      <div>
                        <p className="font-bold text-foreground">{selectedClient.companyName}</p>
                        <p className="text-sm text-muted-foreground">{selectedClient.cpfCnpj}</p>
                      </div>
                    </div>
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => setStep('clients')}
                      className="text-[#7C3AED] border-[#7C3AED] hover:bg-[#7C3AED] hover:text-white"
                    >
                      Alterar
                    </Button>
                  </div>
                </CardContent>
              </Card>
            ) : (
              <Card className="border-none shadow-md mb-6 border-l-4 border-l-amber-400">
                <CardContent className="p-5">
                  <div className="flex items-center justify-between">
                    <p className="text-sm text-muted-foreground">Cliente não encontrado. Selecione outro cliente.</p>
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => setStep('clients')}
                      className="text-[#7C3AED] border-[#7C3AED] hover:bg-[#7C3AED] hover:text-white"
                    >
                      Selecionar
                    </Button>
                  </div>
                </CardContent>
              </Card>
            )}

            {/* Service Selection - Radio list */}
            <Card className="border-none shadow-md mb-6">
              <CardContent className="p-6">
                <div className="flex items-center justify-between mb-1">
                  <h3 className="text-lg font-bold text-foreground">Serviço</h3>
                  <button onClick={async () => { setReloadingServices(true); await reloadServices(); setReloadingServices(false); toast.success('Serviços atualizados') }} disabled={reloadingServices} className="p-2 rounded-lg hover:bg-muted text-muted-foreground hover:text-[#7C3AED] transition-colors disabled:opacity-50" title="Recarregar serviços"><RefreshCw className={`w-4 h-4 ${reloadingServices ? 'animate-spin' : ''}`} /></button>
                </div>
                <p className="text-sm text-muted-foreground mb-4">Selecione o serviço prestado</p>

                {loadingServices ? (
                  <div className="flex items-center justify-center py-8">
                    <Loader2 className="w-6 h-6 text-[#7C3AED] animate-spin" />
                    <span className="ml-3 text-muted-foreground text-sm">Carregando serviços...</span>
                  </div>
                ) : !services || services.length === 0 ? (
                  <div className="text-center py-8 text-muted-foreground">
                    <FileText className="w-10 h-10 mx-auto mb-2 text-muted-foreground" />
                    <p className="font-medium text-sm">Nenhum serviço cadastrado</p>
                    <Button
                      type="button"
                      onClick={() => router.push('/configuracoes/servicos')}
                      className="mt-3 bg-[#7C3AED] hover:bg-[#6D28D9] text-white"
                    >
                      Cadastrar serviço
                    </Button>
                  </div>
                ) : (
                  <div className="space-y-2">
                    {(services || []).map((service) => (
                      <button
                        key={service.id}
                        type="button"
                        onClick={() => {
                          setSelectedService(service.id)
                          if (service.defaultValue && service.defaultValue > 0) {
                            setServiceValue(numberToMoneyDigits(service.defaultValue))
                          }
                        }}
                        className={`w-full text-left flex items-center gap-3 p-4 rounded-xl border-2 transition-all ${
                          selectedService === service.id
                            ? 'border-[#7C3AED] bg-[#FAF5FF] dark:bg-[#7C3AED]/20'
                            : 'border-border hover:border-muted-foreground/40 hover:bg-accent/40'
                        }`}
                      >
                        <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center flex-shrink-0 ${
                          selectedService === service.id
                            ? 'border-[#7C3AED] bg-[#7C3AED]'
                            : 'border-border'
                        }`}>
                          {selectedService === service.id && <Check className="w-3 h-3 text-white" />}
                        </div>
                        <div className="flex-1 min-w-0">
                          <p className={`font-medium ${selectedService === service.id ? 'text-[#7C3AED] dark:text-[#C4B5FD]' : 'text-foreground'}`}>
                            {service.name}
                          </p>
                          {service.description && (
                            <p className={`text-sm truncate ${selectedService === service.id ? 'text-foreground/80' : 'text-muted-foreground'}`}>{service.description}</p>
                          )}
                        </div>
                        <div className="flex flex-col items-end flex-shrink-0">
                          {service.defaultValue && service.defaultValue > 0 ? (
                            <span className={`text-sm font-semibold ${selectedService === service.id ? 'text-[#7C3AED] dark:text-[#C4B5FD]' : 'text-foreground'}`}>
                              {service.defaultValue.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' })}
                            </span>
                          ) : null}
                          <span className={`text-xs ${selectedService === service.id ? 'text-foreground/60' : 'text-muted-foreground'}`}>{service.cnae}</span>
                        </div>
                      </button>
                    ))}
                  </div>
                )}
              </CardContent>
            </Card>

            {/* Value */}
            <Card className="border-none shadow-md mb-6">
              <CardContent className="p-6">
                <h3 className="text-lg font-bold text-foreground mb-4">Valor do Serviço</h3>
                <div className="max-w-sm">
                  <Input
                    value={formatMoney(serviceValue)}
                    onChange={(e) => setServiceValue(extractMoneyDigits(e.target.value))}
                    placeholder="R$ 0,00"
                    className="h-14 text-xl font-bold bg-card border-border"
                  />
                </div>
              </CardContent>
            </Card>

            {/* ISS Retido na Fonte */}
            <Card className="border-none shadow-md mb-6">
              <CardContent className="p-6">
                <div className="flex items-center justify-between">
                  <div>
                    <h3 className="text-lg font-bold text-foreground">ISS Retido na Fonte?</h3>
                    <p className="text-sm text-muted-foreground mt-0.5">Ative se o ISS será retido pelo tomador</p>
                  </div>
                  <label className="relative inline-flex items-center cursor-pointer">
                    <input
                      type="checkbox"
                      checked={issRetido}
                      onChange={(e) => setIssRetido(e.target.checked)}
                      className="sr-only peer"
                    />
                    <div className="w-11 h-6 bg-gray-300 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full rtl:peer-checked:after:-translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:start-[2px] after:bg-card after:border after:border-border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-[#7C3AED]"></div>
                  </label>
                </div>

                {issRetido && (
                  <div className="mt-6 pt-6 border-t border-border space-y-5">
                    {/* Responsável pela Retenção */}
                    <div className="space-y-2">
                      <Label className="text-sm font-semibold text-foreground">Responsável pela Retenção</Label>
                      <Select value={responsavelRetencao} onValueChange={setResponsavelRetencao}>
                        <SelectTrigger className="h-11 bg-card border-border">
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="TOMADOR">Tomador do Serviço</SelectItem>
                          <SelectItem value="INTERMEDIARIO">Intermediário</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>

                    {/* Alíquota ISS */}
                    <div className="space-y-2">
                      <Label className="text-sm font-semibold text-foreground">Alíquota ISS (%)</Label>
                      <Input
                        value={formatPercent(aliquotaIss)}
                        onChange={(e) => setAliquotaIss(extractMoneyDigits(e.target.value))}
                        placeholder="0,00%"
                        className="h-11 bg-card border-border max-w-xs"
                      />
                    </div>

                    {/* Valor Total Retido */}
                    <div className="space-y-2">
                      <Label className="text-sm font-semibold text-foreground">Valor Total Retido</Label>
                      <Input
                        value={formatMoney(valorTotalRetido)}
                        onChange={(e) => setValorTotalRetido(extractMoneyDigits(e.target.value))}
                        placeholder="R$ 0,00"
                        className="h-11 bg-card border-border max-w-xs"
                      />
                    </div>
                  </div>
                )}
              </CardContent>
            </Card>

            {/* Action Buttons */}
            <div className="flex gap-4">
              <Button
                variant="outline"
                onClick={() => setStep('clients')}
                className="flex-1 h-12 border-border hover:bg-background font-semibold"
              >
                Voltar
              </Button>
              <Button
                onClick={handleContinue}
                disabled={!selectedService || !serviceValue}
                className="flex-1 h-12 bg-[#7C3AED] hover:bg-[#6D28D9] text-white font-semibold disabled:opacity-50 disabled:cursor-not-allowed"
              >
                Continuar para Revisão
              </Button>
            </div>
          </div>
        </div>
      </DashboardLayout>
    )
  }

  // ====================================================
  // STEP 3 - REVIEW
  // ====================================================
  if (step === 'review') {
    return (
      <DashboardLayout>
        {licenseModal}
        <div className="min-h-screen bg-background p-4 sm:p-6 lg:p-8">
          <div className="max-w-7xl mx-auto">
            {/* Progress bar */}
            <div className="mb-8">
              <div className="flex items-center justify-center gap-2 sm:gap-3 mb-6">
                <button onClick={() => setStep('clients')} className="flex items-center gap-1.5 sm:gap-2 cursor-pointer">
                  <div className="w-8 h-8 sm:w-10 sm:h-10 rounded-full bg-gradient-to-r from-[#7C3AED] to-[#6D28D9] text-white flex items-center justify-center font-bold shadow-lg">
                    <Check className="w-4 h-4 sm:w-5 sm:h-5" />
                  </div>
                  <span className="text-xs sm:text-sm font-medium text-[#7C3AED]">Cliente</span>
                </button>
                <div className="w-8 sm:w-20 h-1 bg-gradient-to-r from-[#7C3AED] to-[#6D28D9]"></div>
                <button onClick={() => setStep('service')} className="flex items-center gap-1.5 sm:gap-2 cursor-pointer">
                  <div className="w-8 h-8 sm:w-10 sm:h-10 rounded-full bg-gradient-to-r from-[#7C3AED] to-[#6D28D9] text-white flex items-center justify-center font-bold shadow-lg">
                    <Check className="w-4 h-4 sm:w-5 sm:h-5" />
                  </div>
                  <span className="text-xs sm:text-sm font-medium text-[#7C3AED]">Serviço</span>
                </button>
                <div className="w-8 sm:w-20 h-1 bg-gradient-to-r from-[#7C3AED] to-[#6D28D9]"></div>
                <div className="flex items-center gap-1.5 sm:gap-2">
                  <div className="w-8 h-8 sm:w-10 sm:h-10 rounded-full bg-gradient-to-r from-[#7C3AED] to-[#6D28D9] text-white flex items-center justify-center font-bold shadow-lg animate-pulse text-sm sm:text-base">
                    3
                  </div>
                  <span className="text-xs sm:text-sm font-medium text-[#7C3AED]">Revisão</span>
                </div>
              </div>
            </div>

            {/* Header */}
            <div className="mb-8 relative">
              <div className="hidden dark:block absolute inset-0 bg-[#7C3AED]/10 rounded-3xl -z-10"></div>
              <div className="py-6 px-6">
                <h1 className="text-2xl sm:text-3xl lg:text-4xl font-bold text-foreground mb-2">
                  Revisão da Nota Fiscal
                </h1>
                <p className="text-muted-foreground">
                  Confira todos os dados antes de emitir a NFS-e
                </p>
              </div>
            </div>

            <div className="grid lg:grid-cols-3 gap-6">
              {/* Left Column - Details */}
              <div className="lg:col-span-2 space-y-6">
                {/* Client Info */}
                <Card className="border-none shadow-xl overflow-hidden">
                  <div className="h-2 bg-gradient-to-r from-blue-500 to-blue-600"></div>
                  <CardHeader className="bg-blue-50 dark:bg-blue-950/30 border-b">
                    <CardTitle className="text-xl flex items-center gap-3">
                      <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-blue-500 to-blue-600 flex items-center justify-center shadow-lg">
                        <User className="w-6 h-6 text-white" />
                      </div>
                      Dados do Cliente
                    </CardTitle>
                  </CardHeader>
                  <CardContent className="p-6">
                    <div className="space-y-5">
                      <div className="flex items-start gap-4">
                        <div className="w-16 h-16 rounded-2xl bg-gradient-to-br from-blue-500 to-blue-600 flex items-center justify-center text-white font-bold text-2xl shadow-lg flex-shrink-0">
                          {selectedClient?.companyName.charAt(0)}
                        </div>
                        <div className="flex-1">
                          <p className="text-xs text-muted-foreground uppercase tracking-wide mb-1">
                            Nome/Razão Social
                          </p>
                          <p className="font-bold text-foreground text-xl mb-2">
                            {selectedClient?.companyName}
                          </p>
                          <div className="grid grid-cols-2 gap-4">
                            <div>
                              <p className="text-xs text-muted-foreground uppercase tracking-wide mb-1">
                                Documento
                              </p>
                              <p className="font-medium text-foreground">
                                {selectedClient?.documentType}: {selectedClient?.cpfCnpj}
                              </p>
                            </div>
                            <div>
                              <p className="text-xs text-muted-foreground uppercase tracking-wide mb-1">
                                Email
                              </p>
                              <p className="font-medium text-foreground">
                                {selectedClient?.email || 'Não informado'}
                              </p>
                            </div>
                          </div>
                        </div>
                      </div>
                      {selectedClient?.address && (
                        <div className="pt-4 border-t">
                          <p className="text-xs text-muted-foreground uppercase tracking-wide mb-2">
                            Endereço Completo
                          </p>
                          <p className="font-medium text-foreground">
                            {[
                              selectedClient.address.logradouro,
                              selectedClient.address.numero,
                              selectedClient.address.bairro,
                              selectedClient.address.municipio,
                              selectedClient.address.estado,
                            ]
                              .filter(Boolean)
                              .join(', ') || 'Não informado'}
                          </p>
                        </div>
                      )}
                    </div>
                  </CardContent>
                </Card>

                {/* Service Info */}
                <Card className="border-none shadow-xl overflow-hidden">
                  <div className="h-2 bg-gradient-to-r from-green-500 to-emerald-600"></div>
                  <CardHeader className="bg-green-50 dark:bg-green-950/30 border-b">
                    <CardTitle className="text-xl flex items-center gap-3">
                      <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-green-500 to-emerald-600 flex items-center justify-center shadow-lg">
                        <FileText className="w-6 h-6 text-white" />
                      </div>
                      Dados do Serviço
                    </CardTitle>
                  </CardHeader>
                  <CardContent className="p-6">
                    <div className="space-y-5">
                      <div>
                        <p className="text-xs text-muted-foreground uppercase tracking-wide mb-2">
                          Serviço Prestado
                        </p>
                        <p className="font-bold text-foreground text-lg mb-2">
                          {selectedServiceData?.name}
                        </p>
                        <div className="grid grid-cols-2 gap-3">
                          <div className="bg-background p-3 rounded-lg">
                            <p className="text-xs text-muted-foreground mb-1">Código</p>
                            <p className="font-semibold text-foreground">
                              {selectedServiceData?.cTribNac}
                            </p>
                          </div>
                          <div className="bg-background p-3 rounded-lg">
                            <p className="text-xs text-muted-foreground mb-1">CNAE</p>
                            <p className="font-semibold text-foreground">
                              {selectedServiceData?.cnae}
                            </p>
                          </div>
                        </div>
                      </div>

                      {issRetido && (
                        <div className="grid grid-cols-2 gap-4 pt-4 border-t">
                          <div>
                            <p className="text-xs text-muted-foreground uppercase tracking-wide mb-2">
                              ISS Retido
                            </p>
                            <p className="font-semibold text-foreground">Sim</p>
                          </div>
                          <div>
                            <p className="text-xs text-muted-foreground uppercase tracking-wide mb-2">
                              Responsável
                            </p>
                            <p className="font-semibold text-foreground">
                              {responsavelRetencao === 'TOMADOR' ? 'Tomador' : 'Intermediário'}
                            </p>
                          </div>
                          <div>
                            <p className="text-xs text-muted-foreground uppercase tracking-wide mb-2">
                              Alíquota ISS
                            </p>
                            <p className="font-semibold text-foreground">{formatPercent(aliquotaIss) || '0%'}</p>
                          </div>
                          <div>
                            <p className="text-xs text-muted-foreground uppercase tracking-wide mb-2">
                              Valor Retido
                            </p>
                            <p className="font-semibold text-foreground">{formatMoney(valorTotalRetido) || 'R$ 0,00'}</p>
                          </div>
                        </div>
                      )}
                    </div>
                  </CardContent>
                </Card>

                {/* Send Copy Option */}
                <Card className="border-none shadow-lg bg-amber-50 dark:bg-amber-950/30 border-2 border-amber-200 dark:border-amber-700/40 overflow-hidden">
                  <CardContent className="p-6">
                    <div className="flex items-start gap-4">
                      <div className="flex items-center h-6">
                        <input
                          type="checkbox"
                          id="send-copy"
                          checked={sendCopy}
                          onChange={(e) => setSendCopy(e.target.checked)}
                          className="w-5 h-5 text-[#7C3AED] rounded focus:ring-[#7C3AED] cursor-pointer"
                        />
                      </div>
                      <div className="flex-1">
                        <Label
                          htmlFor="send-copy"
                          className="cursor-pointer font-bold text-foreground text-base mb-1 block"
                        >
                          Enviar cópia por email
                        </Label>
                        <p className="text-sm text-foreground">
                          Uma cópia da NFS-e será enviada automaticamente para{' '}
                          <span className="font-semibold">
                            {selectedClient?.email || 'o email do cliente'}
                          </span>
                        </p>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              </div>

              {/* Right Column - Summary */}
              <div className="space-y-6">
                {/* Value Summary */}
                <Card className="border-none shadow-xl overflow-hidden lg:sticky lg:top-8">
                  <div className="h-2 bg-gradient-to-r from-[#7C3AED] via-[#8B5CF6] to-[#6D28D9]"></div>
                  <CardHeader className="bg-gradient-to-br from-[#7C3AED] to-[#6D28D9] text-white">
                    <CardTitle className="text-xl flex items-center justify-between">
                      <span>Resumo Financeiro</span>
                      <div className="w-8 h-8 rounded-lg bg-white/20 flex items-center justify-center">
                        <span className="text-lg font-bold">$</span>
                      </div>
                    </CardTitle>
                  </CardHeader>
                  <CardContent className="p-6 space-y-4">
                    <div className="space-y-4">
                      <div className="flex justify-between items-center pb-4 border-b-2 border-border">
                        <div>
                          <p className="text-xs text-muted-foreground uppercase tracking-wide mb-1">
                            Valor Bruto
                          </p>
                          <p className="font-bold text-foreground text-lg">
                            {formatMoney(serviceValue) || 'R$ 0,00'}
                          </p>
                        </div>
                      </div>

                      {issRetido && (
                        <div className="bg-red-50 p-4 rounded-xl border-2 border-red-100">
                          <div className="flex justify-between items-center mb-2">
                            <p className="text-xs text-red-600 uppercase tracking-wide font-semibold">
                              ISS Retido
                            </p>
                            <p className="text-xs bg-red-100 text-red-700 px-2 py-1 rounded-full font-bold">
                              {formatPercent(aliquotaIss) || '0%'}
                            </p>
                          </div>
                          <p className="font-bold text-red-600 text-lg">
                            - {formatMoney(valorTotalRetido) || 'R$ 0,00'}
                          </p>
                        </div>
                      )}

                      <div className="bg-gradient-to-br from-[#7C3AED]/10 to-[#6D28D9]/5 p-5 rounded-xl border-2 border-[#7C3AED]/20">
                        <p className="text-xs text-muted-foreground uppercase tracking-wide mb-2 font-semibold">
                          Valor Líquido
                        </p>
                        <p className="text-3xl font-bold text-[#7C3AED]">
                          {numericValue > 0 ? (parseFloat(netValue)).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' }) : 'R$ 0,00'}
                        </p>
                        <p className="text-xs text-muted-foreground mt-2">
                          Valor a receber após impostos
                        </p>
                      </div>
                    </div>

                    <div className="pt-4 space-y-3 border-t-2 border-border">
                      <Button
                        variant="outline"
                        onClick={() => setStep('service')}
                        className="w-full h-12 border-2 border-border hover:bg-background font-semibold"
                      >
                        Editar Dados
                      </Button>
                      <Button
                        onClick={handleConfirmEmit}
                        disabled={emitting}
                        className="w-full h-14 bg-gradient-to-r from-[#7C3AED] to-[#6D28D9] hover:from-[#6D28D9] hover:to-[#5B21B6] shadow-lg hover:shadow-xl transition-all duration-200 text-white font-bold text-base"
                      >
                        {emitting ? (
                          <>
                            <Loader2 className="w-5 h-5 mr-2 animate-spin" />
                            Emitindo...
                          </>
                        ) : (
                          <>
                            <Check className="w-5 h-5 mr-2" />
                            Confirmar e Emitir NFS-e
                          </>
                        )}
                      </Button>
                    </div>
                  </CardContent>
                </Card>

                {/* Info Box */}
                <Card className="border-none shadow-lg bg-blue-50 dark:bg-blue-950/30 border-2 border-blue-200 dark:border-blue-700/40">
                  <CardContent className="p-5">
                    <div className="flex gap-3">
                      <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-blue-500 to-blue-600 flex items-center justify-center flex-shrink-0 shadow-lg">
                        <span className="text-white text-xl font-bold">ℹ</span>
                      </div>
                      <div>
                        <p className="font-bold text-foreground mb-2 text-base">
                          Atenção
                        </p>
                        <p className="text-sm text-foreground leading-relaxed">
                          Após a emissão, a nota fiscal não poderá ser editada.
                          Certifique-se de que todas as informações estão corretas antes
                          de prosseguir.
                        </p>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              </div>
            </div>
          </div>

          {/* Success Modal */}
          <Dialog open={showSuccessModal} onOpenChange={setShowSuccessModal}>
            <DialogContent className="max-w-md text-center">
              <DialogHeader>
                <DialogTitle className="text-2xl">
                  Nota Emitida com Sucesso!
                </DialogTitle>
                <DialogDescription className="sr-only">
                  A nota fiscal foi emitida com sucesso e está pronta para visualização
                </DialogDescription>
              </DialogHeader>
              <div className="flex flex-col items-center py-6">
                <div className="w-20 h-20 bg-[#F3E8FF] rounded-full flex items-center justify-center mb-6">
                  <Check className="w-10 h-10 text-[#7C3AED]" />
                </div>
                <p className="text-muted-foreground mb-6">
                  {emittedNoteNumber
                    ? `NFS-e N. ${emittedNoteNumber} foi gerada com sucesso`
                    : 'NFS-e foi gerada com sucesso'}
                </p>
                <div className="flex gap-3 w-full">
                  <Button
                    variant="outline"
                    onClick={resetWizard}
                    className="flex-1"
                  >
                    Voltar ao Início
                  </Button>
                  <Button
                    className="flex-1 bg-[#7C3AED] hover:bg-[#6D28D9] text-white"
                    onClick={() => router.push(emittedNoteId ? `/notas-emitidas/${emittedNoteId}` : '/notas-emitidas')}
                  >
                    Visualizar NFS-e
                  </Button>
                </div>
              </div>
            </DialogContent>
          </Dialog>
        </div>
      </DashboardLayout>
    )
  }

  return null
}

function NovaNotaPageFallback() {
  return (
    <DashboardLayout>
      <div className="min-h-screen bg-background p-8">
        <div className="max-w-5xl mx-auto flex items-center justify-center py-20">
          <div className="flex items-center gap-3 text-muted-foreground">
            <Loader2 className="w-6 h-6 text-[#7C3AED] animate-spin" />
            <span>Carregando emissao de nota...</span>
          </div>
        </div>
      </div>
    </DashboardLayout>
  )
}

export default function NovaNotaPage() {
  return (
    <Suspense fallback={<NovaNotaPageFallback />}>
      <NovaNotaPageContent />
    </Suspense>
  )
}
